async function updateDescriptions() {
  try {
    await client.connect();
    console.log('✅ Connected to MongoDB');
    
    const db = client.db('uraerotech');
    const products = await db.collection('Product').find({}).toArray();
    
    let updated = 0;
    for (const product of products) {
      const newDescription = extendedDescriptions[product.slug];
      if (newDescription) {
        await db.collection('Product').updateOne(
          { _id: product._id },
          { $set: { description: newDescription, updatedAt: new Date() } }
        );
        updated++;
        console.log(`✅ Updated: ${product.name}`);
      }
    }
    
    console.log(`\n🎉 Updated ${updated} product descriptions!`);
    
  } catch (error) {
    console.error('❌ Error updating descriptions:', error);
    throw error;
  } finally {
    await client.close();
    console.log('✅ Database connection closed');
  }
}

updateDescriptions().catch(console.error);


